func (r *Redirect) Messages() []FlashMessage {
	flashMessages := make([]FlashMessage, 0)

	for _, msg := range r.c.flashMessages {
		if !msg.isOldInput {
			flashMessages = append(flashMessages, FlashMessage{
				Key:	msg.key,
				Value:	msg.value,
				Level:	msg.level,
			})
		}
	}

	return flashMessages
}
